const _h = this.helpers;
const fetch = async (url, init = {}) => {
  const opts = { method: init.method || 'GET', url, headers: { ...(init.headers || {}) }, json: true, timeout: 10000, returnFullResponse: false };
  if (opts.headers['Content-Type']) delete opts.headers['Content-Type'];
  if (opts.headers['content-type']) delete opts.headers['content-type'];
  if (init.body !== undefined) {
    if (typeof init.body === 'string') { try { opts.body = JSON.parse(init.body); } catch { opts.body = init.body; } }
    else opts.body = init.body;
  }
  try {
    const data = await _h.httpRequest(opts);
    return { ok: true, status: 200, json: async () => data, text: async () => (typeof data === 'string' ? data : JSON.stringify(data)) };
  } catch (e) {
    const status = (e && e.statusCode) || (e && e.response && e.response.statusCode) || (e && e.cause && e.cause.statusCode) || 500;
    let errBody = (e && e.response && e.response.body) ?? (e && e.cause && e.cause.body) ?? null;
    if (errBody && typeof errBody !== 'string') { try { errBody = JSON.stringify(errBody); } catch { errBody = String(errBody); } }
    if (!errBody && e && e.message) errBody = e.message;
    return { ok: false, status, json: async () => { try { return JSON.parse(errBody); } catch { return errBody; } }, text: async () => String(errBody) };
  }
};

const body = $input.first().json.body || {};
const sb = $vars.CARGLASS_SUPABASE_URL;
const headers = { apikey: $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY, Authorization: 'Bearer ' + $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY };
let filter;
if (body.appointment_id) filter = `id=eq.${body.appointment_id}`;
else if (body.booking_ref) filter = `booking_reference=eq.${encodeURIComponent(body.booking_ref)}`;
else return [{ json: { ok: false, error_code: 'MISSING_IDENTIFIER', message_for_agent: 'Bitte Buchungsreferenz angeben.' } }];
const url = `${sb}/rest/v1/appointments?${filter}&select=id,booking_reference,status,scheduled_start,scheduled_end,eta_ready_at,branch_id,service_id,branches(name,city,phone),services(name_de,default_duration_minutes)`;
const r = await fetch(url, { headers });
if (!r.ok) return [{ json: { ok: false, error_code: 'SUPABASE_ERROR', message_for_agent: 'Bitte versuchen Sie es erneut.' } }];
const data = await r.json();
if (!data.length) return [{ json: { ok: true, data: { found: false, appointment: null } } }];
const a = data[0];
return [{ json: { ok: true, data: { found: true, appointment: {
  id: a.id,
  booking_reference: a.booking_reference,
  status: a.status,
  scheduled_start: a.scheduled_start,
  scheduled_end: a.scheduled_end,
  eta_ready_at: a.eta_ready_at,
  branch_name: a.branches ? a.branches.name : null,
  branch_city: a.branches ? a.branches.city : null,
  branch_phone: a.branches ? a.branches.phone : null,
  service_name: a.services ? a.services.name_de : null,
} } } }];
